SELECT AVG(sentiment_score) AS average_sentiment_score
FROM sector_sentiment
WHERE sector_id = 1;

SELECT sector_name, COUNT(*) AS number_of_sectors
FROM sectors
GROUP BY sector_name;

SELECT sector_id, MAX(sentiment_score) AS highest_sentiment_score
FROM sector_sentiment
GROUP BY sector_id;

SELECT AVG(sentiment_score) AS average_sentiment_score
FROM sentiment_data
WHERE date BETWEEN '2023-01-01' AND '2023-12-31';

SELECT AVG(performance_score) AS typical_performance_score, MAX(performance_score) AS highest_performance_score
FROM sector_performance
WHERE date BETWEEN '2023-01-01' AND '2023-12-31';

SELECT COUNT(*) AS total_articles
FROM news_articles
WHERE publication_date BETWEEN '2023-01-01' AND '2023-12-31';

SELECT sector_name, description
FROM sectors
WHERE sector_id = 1;

SELECT source_name, source_reliability_score, source_url
FROM news_sources
ORDER BY source_reliability_score DESC;
